    public static void fixJettyStubHttpServer(String filePath) throws Exception {
        JavaParser parser = new JavaParser();
        ParseResult<CompilationUnit> result = parser.parse(new File(filePath));
        CompilationUnit cu = result.getResult().orElseThrow();

        cu.getImports().stream()
            .filter(i -> i.getNameAsString().equals("org.eclipse.jetty.server.nio.SelectChannelConnector"))
            .findFirst()
            .ifPresent(cu::remove);

        cu.getImports().stream()
            .filter(i -> i.getNameAsString().equals("org.eclipse.jetty.server.Connector"))
            .findFirst()
            .ifPresent(i -> i.setName("org.eclipse.jetty.server.ServerConnector"));

        cu.getClassByName("JettyStubHttpServer").ifPresent(cls -> {
            cls.getFieldByName("httpConnector").ifPresent(field -> {
                field.setType("ServerConnector");
            });

            cls.getConstructorByName("JettyStubHttpServer").ifPresent(ctor -> {
                ctor.getBody().getStatements().stream()
                    .filter(s -> s.toString().contains("setSendServerVersion"))
                    .findFirst()
                    .ifPresent(stmt -> {
                        int idx = ctor.getBody().getStatements().indexOf(stmt);
                        if (idx >= 0) ctor.getBody().removeStatement(idx);
                    });

                ctor.getBody().getStatements().stream()
                    .filter(s -> s.toString().contains("setSendDateHeader"))
                    .findFirst()
                    .ifPresent(stmt -> {
                        int idx = ctor.getBody().getStatements().indexOf(stmt);
                        if (idx >= 0) ctor.getBody().removeStatement(idx);
                    });

                ctor.getBody().getStatements().stream()
                    .filter(s -> s.toString().contains("SelectChannelConnector"))
                    .findFirst()
                    .ifPresent(stmt -> {
                        int idx = ctor.getBody().getStatements().indexOf(stmt);
                        if (idx >= 0) {
                            ctor.getBody().removeStatement(idx);
                            ctor.getBody().addStatement(
                                new BlockStmt().addStatement(
                                    "this.httpConnector = new ServerConnector(this.server);"
                                ).getStatement(0)
                            );
                        }
                    });

                ctor.getBody().getStatements().stream()
                    .filter(s -> s.toString().contains("httpConnector.setPort"))
                    .findFirst()
                    .ifPresent(stmt -> {
                        int idx = ctor.getBody().getStatements().indexOf(stmt);
                        if (idx >= 0) ctor.getBody().removeStatement(idx);
                    });
            });

            cls.getMethodByName("getPort").ifPresent(method -> {
                method.getBody().ifPresent(body -> {
                    body.getStatements().clear();
                    body.addStatement("return ((ServerConnector) this.server.getConnectors()[0]).getLocalPort();");
                });
            });
        });

        Files.writeString(Paths.get(filePath), cu.toString());
        System.out.println("Fixed JettyStubHttpServer.java");
    }

    public static void fixJadlerHandler(String filePath) throws Exception {
        JavaParser parser = new JavaParser();
        ParseResult<CompilationUnit> result = parser.parse(new File(filePath));
        CompilationUnit cu = result.getResult().orElseThrow();

        cu.getImports().stream()
            .filter(i -> i.getNameAsString().equals("org.eclipse.jetty.server.Request"))
            .findFirst()
            .ifPresent(cu::remove);

        cu.getClassByName("JadlerHandler").ifPresent(cls -> {
            cls.getMethodByName("handle").ifPresent(method -> {
                method.getParameter(1).setType("jakarta.servlet.http.HttpServletRequest");
                method.getParameter(2).setType("jakarta.servlet.http.HttpServletResponse");

                method.getBody().ifPresent(body -> {
                    body.getStatements().stream()
                        .filter(s -> s.toString().contains("baseRequest.setHandled"))
                        .findFirst()
                        .ifPresent(stmt -> {
                            int idx = body.getStatements().indexOf(stmt);
                            if (idx >= 0) {
                                body.getStatements().set(idx, 
                                    new BlockStmt().addStatement("response.setHandled(true);").getStatement(0)
                                );
                            }
                        });
                });
            });
        });

        Files.writeString(Paths.get(filePath), cu.toString());
        System.out.println("Fixed JadlerHandler.java");
    }
}

